const std = @import("std");

pub fn countUsers(allocator: std.mem.Allocator) !usize {
    var user_map = std.StringHashMap(u32).init(allocator);
    defer user_map.deinit();
    try user_map.put("ada", 1);
    return user_map.size;
}

const std = @import("std");

const Schema = struct {
    items: std.json.ArrayHashMap(Item),
};

const Item = struct { name: []const u8 };

pub fn parse(allocator: std.mem.Allocator, bytes: []const u8) !usize {
    const parsed = try std.json.parseFromSlice(Schema, allocator, bytes, .{ .allocate = .alloc_always });
    defer parsed.deinit();
    return parsed.value.items.map.size;
}

const std = @import("std");

pub fn countUsers(allocator: std.mem.Allocator) !usize {
    var user_map = std.StringHashMap(u32).init(allocator);
    defer user_map.deinit();
    try user_map.put("ada", 1);
    return user_map.count();
}
